// mm/src/components/WorkflowContainer.js
import React, { useEffect, useState } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { motion } from 'framer-motion';
import { ChevronLeft, ChevronRight } from 'lucide-react';

import { useWorkflow } from '../store/workflowContext';
import SaveProgressPrompt from './SaveProgressPrompt';
import Progress from './ui/Progress';

// Global step rail at the top of the workflow
const steps = [
  { num: 1, label: 'Upload', route: '/workflow/start' },
  { num: 2, label: 'Design', route: '/workflow/design' },
  { num: 3, label: 'Preview', route: '/workflow/preview' },
  { num: 4, label: 'Details', route: '/workflow/details' },
  { num: 5, label: 'Download', route: '/workflow/download' },
];

const WorkflowContainer = ({
  children,
  title,
  description,
  step,
  canProceed = false,
  onNext,
  onPrevious,
  hideNext = false,
  disableSavePrompt = false,
}) => {
  const navigate = useNavigate();
  const location = useLocation();

  const {
    currentStep,
    setCurrentStep,
    bookDetails,
    manuscriptFiles,
    preferences,
  } = useWorkflow();

  const [showSavePrompt, setShowSavePrompt] = useState(false);

  const totalSteps = steps.length;

  useEffect(() => {
    if (setCurrentStep) {
      setCurrentStep(step);
    }
  }, [step, setCurrentStep]);

  const progressPercentage = Math.round((step / totalSteps) * 100);

  const hasProgress = () => {
    return (
      (bookDetails && Object.keys(bookDetails || {}).length > 0) ||
      (manuscriptFiles && manuscriptFiles.length > 0) ||
      (preferences && Object.keys(preferences || {}).length > 0)
    );
  };

  const handleNext = () => {
    // If parent provided custom onNext, use that and *do not* auto-navigate.
    if (onNext) {
      onNext();
      return;
    }

    // Default behavior: navigate to the next workflow route
    const isAuthenticated = false;

    if (!disableSavePrompt && !isAuthenticated && hasProgress() && step === 1) {
      setShowSavePrompt(true);
      return;
    }

    if (step < totalSteps) {
      // NOTE: steps is 0-based, step is 1-based
      navigate(steps[step].route);
    }
  };

  const handleSaveWithoutAccount = () => {
    setShowSavePrompt(false);

    if (onNext) {
      onNext();
      return;
    }

    if (step < totalSteps) {
      navigate(steps[step].route);
    }
  };

  const handlePrevious = () => {
    // If parent provided custom onPrevious, use that.
    if (onPrevious) {
      onPrevious();
      return;
    }

    // Default behavior: go one global step back, or home from first step
    if (step > 1) {
      navigate(steps[step - 2].route);
    } else {
      navigate('/');
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 via-slate-50 to-slate-100">
      <div className="container mx-auto px-4 py-10 max-w-6xl">
        {/* Header: title, description, progress bar */}
        <div className="mb-8">
          <div className="flex items-center justify-between mb-6">
            <div>
              <h1 className="text-4xl font-extrabold text-slate-900 mb-2 tracking-tight">
                {title}
              </h1>
              <p className="text-lg text-slate-500">{description}</p>
            </div>
            <div className="text-right">
              <p className="text-sm text-slate-500 mb-2">
                Step {step} of {totalSteps}
              </p>
              <div className="w-64">
                <Progress value={progressPercentage} />
              </div>
            </div>
          </div>

          {/* Top step rail */}
          <div className="flex items-center justify-center space-x-4 mb-8">
            {steps.map((s, i) => (
              <div key={s.num} className="flex items-center flex-1">
                <div
                  className={`w-10 h-10 rounded-full flex items-center justify-center text-sm font-medium transition-colors
                  ${
                    s.num <= step
                      ? 'bg-blue-600 text-white'
                      : s.num === step + 1
                      ? 'bg-sky-100 text-sky-600'
                      : 'bg-slate-100 text-slate-500'
                  }`}
                >
                  {s.num}
                </div>
                <span className="ml-3 text-sm font-medium hidden sm:block text-slate-600">
                  {s.label}
                </span>
                {i < steps.length - 1 && (
                  <div
                    className={`flex-1 h-0.5 mx-4 ${
                      s.num < step ? 'bg-blue-600' : 'bg-slate-200'
                    }`}
                  />
                )}
              </div>
            ))}
          </div>
        </div>

        {/* Animated content */}
        <motion.div
          key={location.pathname}
          initial={{ opacity: 0, y: 12 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0, y: -12 }}
          transition={{ duration: 0.28 }}
        >
          <div className="bg-white rounded-2xl shadow-sm p-8 mb-8">
            {children}
          </div>
        </motion.div>

        {/* Footer buttons */}
        <div className="flex justify-between items-center">
          <button
            onClick={handlePrevious}
            className="inline-flex items-center px-4 py-2 rounded-md border border-slate-200 bg-white text-slate-700"
          >
            <ChevronLeft className="w-4 h-4 mr-2" />{' '}
            <span>{step === 1 ? 'Back to Home' : 'Previous'}</span>
          </button>

          {!hideNext && (
            <button
              onClick={handleNext}
              disabled={!canProceed}
              className={`inline-flex items-center px-5 py-2 rounded-md text-white ${
                canProceed
                  ? 'bg-blue-600 hover:bg-blue-700'
                  : 'bg-slate-300 cursor-not-allowed'
              }`}
            >
              <span className="mr-2">
                {step === totalSteps ? 'Complete' : 'Continue'}
              </span>
              <ChevronRight className="w-4 h-4" />
            </button>
          )}
        </div>
      </div>

      <SaveProgressPrompt
        isOpen={showSavePrompt}
        onClose={() => setShowSavePrompt(false)}
        onSaveWithoutAccount={handleSaveWithoutAccount}
      />
    </div>
  );
};

export default WorkflowContainer;
